)
language plpgsql
security definer
set search_path = public
as $$
declare
  v_uid uuid := auth.uid();
  v_bucket text;
  v_filename text;
  v_intent_id uuid := gen_random_uuid();
begin
  if v_uid is null then
    raise exception 'Authentication required';
  end if;

  if not public.is_org_member(p_org_id) then
    raise exception 'Not a member of organization %', p_org_id;
  end if;

  if coalesce(trim(p_type), '') = '' then
    raise exception 'Document type is required';
