  from public.storage_bucket_config c
  where c.key = 'documents';

  if v_bucket is null or trim(v_bucket) = '' then
    raise exception 'Document upload bucket is not configured';
  end if;

  v_filename := public.sanitize_uploaded_filename(p_client_filename);

  insert into public.org_document_upload_intents (
    id,
    org_id,
    bucket,
    object_path,
    filename,
    mime_type,
    size_bytes,
    created_by
  )
  values (
    v_intent_id,
    p_org_id,
    v_bucket,
    format('orgs/%s/%s/%s', p_org_id, v_intent_id, v_filename),
    v_filename,
    nullif(trim(p_mime_type), ''),
    p_size_bytes,
    v_uid
  );

  return query
  select
    v_intent_id,
    v_bucket,
    format('orgs/%s/%s/%s', p_org_id, v_intent_id, v_filename),
    v_filename,
    nullif(trim(p_mime_type), ''),
    p_size_bytes;
end;
$$;

